/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `bigquery_tables_update_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from bigquery_tables_update_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn bigquery_tables_update_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<Table>, ApiError>, P = ApiPending> + Send + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success {
                stream,
                intro,
                headers,
                ..
            } => {
                let status_code: usize = intro.0.into();

                if status_code < 200 || status_code >= 300 {
                    // Capture body for error parsing
                    let body = body_reader::collect_string(stream);
                    // Try to parse as structured API error
                    if let Ok(error_body) = serde_json::from_str::<ApiErrorBody>(&body) {
                        return Err(ApiError::ApiError(error_body.error));
                    }
                    // Fall back to raw HTTP status error
                    return Err(ApiError::HttpStatus {
                        code: status_code as u16,
                        headers: headers.clone(),
                        body: Some(body),
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: Table = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status_code as u16,
                    headers: headers.clone(),
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

/// GET projects/{projectsId}/datasets/{datasetsId}/tables/{tablesId}
/// Updates information in an existing table. The update method replaces the entire Table resource, whereas the patch method only replaces fields that are provided in the submitted Table resource.
///
/// Simplest API - builds and executes the request in one call.
/// For customization, use `bigquery_tables_update_builder()` + `bigquery_tables_update_execute()`.
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn bigquery_tables_update(
    client: &SimpleHttpClient,
    projectId: &str,
    datasetId: &str,
    tableId: &str,
    autodetect_schema: Option<bool>,
    body: &Table,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<Table>, ApiError>, P = ApiPending> + Send + 'static,
    ApiError,
> {
    let builder = bigquery_tables_update_builder(
        client,
        projectId,
        datasetId,
        tableId,
        autodetect_schema,
        body,
    )?;
    bigquery_tables_update_execute(builder)
}
